+fn parse_order_hint(node_id: &str, fallback: usize) -> usize {
+    node_id
+        .rsplit('_')
+        .next()
+        .and_then(|candidate| candidate.parse::<usize>().ok())
+        .unwrap_or(fallback.saturating_add(10_000))
+}
